@startuml
skinparam classAttributeIconSize 0
left to right direction

abstract class WordFinder << (A,#9fd7df) >> {
  fileCreator()
  replaceInString()
}

class String << (C,#b9d9b9) >> {
  revised
  content
  file
  str
  --
  replaceAll()
}

class PrintWriter << (C,#b9d9b9) >> {
  out
  writer
  --
  close()
  println()
}

class Files << (C,#b9d9b9) >> {
  readString
}

class Scanner << (C,#b9d9b9) >> {
  input
  --
  nextLine()
}

String -left-|> WordFinder

PrintWriter ..> WordFinder
Files ..> WordFinder
Scanner ..> WordFinder
@enduml
